def gen(rng, size):
    n = max(1, min(size, 200))
    loc = [rng.randint(0, 100), rng.randint(0, 100)]
    points = []
    for _ in range(n):
        if rng.random() < 0.05:
            points.append(loc[:])
        else:
            points.append([rng.randint(0, 100), rng.randint(0, 100)])
    angle = rng.randint(0, 359)
    return [points, angle, loc]

