import math

class Solution:
    def visiblePoints(self, points, angle, location):
        px, py = location
        same = 0
        angles = []
        for x, y in points:
            dx, dy = x - px, y - py
            if dx == 0 and dy == 0:
                same += 1
                continue
            a = math.degrees(math.atan2(dy, dx))
            if a < 0:
                a += 360
            angles.append(round(a, 6))
        n = len(angles)
        if n == 0:
            return same
        eps = 1e-6
        best = 0
        for i in range(n):
            start = angles[i]
            count = 0
            for a in angles:
                diff = a - start
                if diff < 0:
                    diff += 360
                if diff <= angle + eps:
                    count += 1
            best = max(best, count)
        return best + same

