var visiblePoints = function(points, angle, location) {
    const [px, py] = location;
    let same = 0;
    const angles = [];
    for (const [x, y] of points) {
        const dx = x - px, dy = y - py;
        if (dx === 0 && dy === 0) {
            same++;
            continue;
        }
        let a = Math.atan2(dy, dx) * 180 / Math.PI;
        if (a < 0) a += 360;
        angles.push(Math.round(a * 1e6) / 1e6);
    }
    angles.sort((x, y) => x - y);
    const n = angles.length;
    if (n === 0) return same;
    const extended = angles.concat(angles.map(a => a + 360));
    const eps = 1e-6;
    let best = 0;
    let j = 0;
    for (let i = 0; i < n; i++) {
        while (j < i + n && extended[j] - angles[i] <= angle + eps) {
            j++;
        }
        best = Math.max(best, j - i);
    }
    return best + same;
};
